package main

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"

	"github.com/spf13/cobra"
)

type Photo struct {
	ID          string    `json:"id"`
	Path        string    `json:"path"`
	Date        time.Time `json:"date"`
	Category    string    `json:"category"`
	Description string    `json:"description"`
}

var (
	photoDate        string
	photoCategory    string
	photoDescription string
	photoPath        string
)

func main() {
	var rootCmd = &cobra.Command{
		Use:   "photoarch",
		Short: "A CLI tool to manage personal digital photography archive",
		Long:  `PhotoArch is a command line tool that helps users manage their personal digital photography archive.`,
	}

	var initCmd = &cobra.Command{
		Use:   "init",
		Short: "Initialize a new photo archive",
		Run: func(cmd *cobra.Command, args []string) {
			initArchive()
		},
	}

	var addCmd = &cobra.Command{
		Use:   "add",
		Short: "Add a new photo to the archive",
		Run: func(cmd *cobra.Command, args []string) {
			addPhoto()
		},
	}

	addCmd.Flags().StringVarP(&photoPath, "path", "p", "", "Path to the photo file (required)")
	addCmd.Flags().StringVarP(&photoDate, "date", "d", time.Now().Format("2006-01-02"), "Date when the photo was taken (YYYY-MM-DD)")
	addCmd.Flags().StringVarP(&photoCategory, "category", "c", "uncategorized", "Category of the photo")
	addCmd.Flags().StringVarP(&photoDescription, "description", "m", "", "Description of the photo")
	addCmd.MarkFlagRequired("path")

	var reportCmd = &cobra.Command{
		Use:   "report",
		Short: "Generate a report of all photos by category",
		Run: func(cmd *cobra.Command, args []string) {
			generateReport()
		},
	}

	rootCmd.AddCommand(initCmd, addCmd, reportCmd)
	rootCmd.Execute()
}

func initArchive() {
	// Create directory structure
	dirs := []string{
		"archive",
		"archive/photos",
		"archive/metadata",
	}

	for _, dir := range dirs {
		err := os.MkdirAll(dir, 0755)
		if err != nil {
			fmt.Printf("Error creating directory %s: %v\n", dir, err)
			return
		}
	}

	// Create initial metadata file
	metadataFile := filepath.Join("archive", "metadata", "photos.json")
	if _, err := os.Stat(metadataFile); os.IsNotExist(err) {
		file, err := os.Create(metadataFile)
		if err != nil {
			fmt.Printf("Error creating metadata file: %v\n", err)
			return
		}
		file.Write([]byte("[]"))
		file.Close()
	}

	fmt.Println("Photo archive initialized successfully.")
}

func addPhoto() {
	metadataPath := filepath.Join("archive", "metadata", "photos.json")

	// Check if archive is initialized
	if _, err := os.Stat(metadataPath); os.IsNotExist(err) {
		fmt.Println("Photo archive not initialized. Please run 'photoarch init' first.")
		return
	}

	// Parse date
	date, err := time.Parse("2006-01-02", photoDate)
	if err != nil {
		fmt.Printf("Invalid date format. Please use YYYY-MM-DD format: %v\n", err)
		return
	}

	// Generate unique ID
	id := fmt.Sprintf("%d", time.Now().UnixNano())

	// Create new photo entry
	photo := Photo{
		ID:          id,
		Path:        photoPath,
		Date:        date,
		Category:    photoCategory,
		Description: photoDescription,
	}

	// Read existing metadata
	data, err := os.ReadFile(metadataPath)
	if err != nil {
		fmt.Printf("Error reading metadata file: %v\n", err)
		return
	}

	var photos []Photo
	err = json.Unmarshal(data, &photos)
	if err != nil {
		fmt.Printf("Error parsing metadata: %v\n", err)
		return
	}

	// Add new photo
	photos = append(photos, photo)

	// Write updated metadata
	updatedData, err := json.MarshalIndent(photos, "", "  ")
	if err != nil {
		fmt.Printf("Error encoding metadata: %v\n", err)
		return
	}

	err = os.WriteFile(metadataPath, updatedData, 0644)
	if err != nil {
		fmt.Printf("Error writing metadata: %v\n", err)
		return
	}

	fmt.Printf("Photo added successfully with ID: %s\n", id)
}

func generateReport() {
	metadataPath := filepath.Join("archive", "metadata", "photos.json")

	// Check if archive is initialized
	if _, err := os.Stat(metadataPath); os.IsNotExist(err) {
		fmt.Println("Photo archive not initialized. Please run 'photoarch init' first.")
		return
	}

	// Read metadata
	data, err := os.ReadFile(metadataPath)
	if err != nil {
		fmt.Printf("Error reading metadata file: %v\n", err)
		return
	}

	var photos []Photo
	err = json.Unmarshal(data, &photos)
	if err != nil {
		fmt.Printf("Error parsing metadata: %v\n", err)
		return
	}

	// Group photos by category
	categories := make(map[string][]Photo)
	for _, photo := range photos {
		categories[photo.Category] = append(categories[photo.Category], photo)
	}

	// Print report
	fmt.Println("Photo Archive Report")
	fmt.Println("===================")
	fmt.Printf("Total Photos: %d\n\n", len(photos))

	fmt.Println("Photos by Category:")
	fmt.Println("-----------------")
	for category, categoryPhotos := range categories {
		fmt.Printf("%s: %d photos\n", category, len(categoryPhotos))
		for _, photo := range categoryPhotos {
			fmt.Printf("  - [%s] %s: %s\n", 
				photo.Date.Format("2006-01-02"), 
				filepath.Base(photo.Path), 
				photo.Description)
		}
		fmt.Println()
	}
}

const { Command } = require('commander');
const fs = require('fs');
const path = require('path');

const program = new Command();

program
  .name('line-counter')
  .description('Count lines in files')
  .version('1.0.0')
  .argument('<files...>', 'file paths to count lines')
  .action((files) => {
    files.forEach(filePath => {
      try {
        const fullPath = path.resolve(filePath);
        const content = fs.readFileSync(fullPath, 'utf8');
        const lineCount = content.split('\n').length;
        console.log(`${filePath}: ${lineCount} lines`);
      } catch (error) {
        if (error.code === 'ENOENT') {
