import { interval } from 'rxjs';
import { switchMap, distinctUntilChanged, catchError, retry } from 'rxjs/operators';

class UrlMonitor {
  constructor(url, pollInterval = 30000) {
    this.url = url;
    this.pollInterval = pollInterval;
    this.lastContent = null;
  }

  fetchUrl() {
    return fetch(this.url)
      .then(response => {
        if (!response.ok) {
          throw new Error(`HTTP error: ${response.status}`);
        }
        return response.text();
      });
  }

  startMonitoring() {
    return interval(this.pollInterval)
      .pipe(
        switchMap(() => {
          console.log(`Polling ${this.url}...`);
          return this.fetchUrl();
        }),
        distinctUntilChanged(),
        catchError(error => {
          console.error(`Error fetching URL: ${error.message}`);
          return [];  // Return empty to continue the stream
        }),
        retry({
          delay: (error, retryCount) => {
            console.log(`Retrying (${retryCount})...`);
            return interval(Math.min(1000 * retryCount, 10000));
          }
        })
      )
      .subscribe({
        next: content => {
          if (this.lastContent !== null && this.lastContent !== content) {
            console.log('Content changed!');
            console.log('New content:', content);
          } else if (this.lastContent === null) {
            console.log('Initial content loaded:', content);
          }
          this.lastContent = content;
        },
        error: error => console.error(`Fatal error: ${error.message}`),
        complete: () => console.log('Monitoring completed')
      });
  }
}

// Usage
const monitor = new UrlMonitor('https://example.com');
const subscription = monitor.startMonitoring();

