use std::path::Path;
use std::fs::{self, File};
use std::io::{self, Read, Write};
use futures::{stream, StreamExt};
use serde::{Deserialize, Serialize};
use tokio::fs::File as AsyncFile;
use tokio::io::{AsyncReadExt, AsyncWriteExt};

#[derive(Serialize, Deserialize)]
struct Config {
    file_paths: Vec<String>,
    output_path: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let config_str = fs::read_to_string("config.json")?;
    let config: Config = serde_json::from_str(&config_str)?;

    // Create a stream of futures for each file read operation
    let file_contents = stream::iter(config.file_paths)
        .map(|path| async move {
            match read_file(&path).await {
                Ok(content) => (path, Ok(content)),
                Err(e) => (path, Err(e)),
            }
        })
        .buffer_unordered(100) // Process up to 100 files concurrently
        .collect::<Vec<_>>()
        .await;

    // Combine all content and handle errors
    let mut combined_content = String::new();

    for (path, result) in file_contents {
        match result {
            Ok(content) => {
                combined_content.push_str(&content);
            },
            Err(e) => {
                eprintln!("Error reading file {}: {}", path, e);
            }
        }
    }

    // Write the combined content to the output file
    let mut output_file = AsyncFile::create(&config.output_path).await?;
    output_file.write_all(combined_content.as_bytes()).await?;

    println!("Successfully processed files and wrote output to {}", config.output_path);

    Ok(())
}

async fn read_file(path: &str) -> io::Result<String> {
    if !Path::new(path).exists() {
        return Err(io::Error::new(io::ErrorKind::NotFound, format!("File not found: {}", path)));
    }

    let mut file = AsyncFile::open(path).await?;
    let mut contents = String::new();
    file.read_to_string(&mut contents).await?;

    Ok(contents)
}

