func main() {
	// Check command-line arguments
	if len(os.Args) < 3 {
		log.Fatal("Usage: program <json_file_path> <api_endpoint>")
	}

	jsonFilePath := os.Args[1]
	apiEndpoint := os.Args[2]

	// Read JSON file
	jsonData, err := ioutil.ReadFile(jsonFilePath)
	if err != nil {
		log.Fatalf("Error reading JSON file: %v", err)
	}

	// Parse JSON data
	var userData User
	if err := json.Unmarshal(jsonData, &userData); err != nil {
		log.Fatalf("Error parsing JSON data: %v", err)
	}

	// Create a Resty client
	client := resty.New()

	// Send POST request
	resp, err := client.R().
		SetHeader("Content-Type", "application/json").
		SetBody(userData).
		Post(apiEndpoint)

	if err != nil {
		log.Fatalf("Error sending POST request: %v", err)
	}

	// Handle response
	if resp.IsSuccess() {
		fmt.Printf("Request successful! Status code: %d\n", resp.StatusCode())
		fmt.Printf("Response body: %s\n", resp.Body())
	} else {
