}

import click
import requests
import sys

@click.command()
@click.option('--file', required=True, type=click.Path(exists=True), help='File containing URLs, one per line')
def fetch_urls(file):
    try:
        with open(file, 'r') as f:
            urls = [line.strip() for line in f if line.strip()]

        for url in urls:
            try:
                response = requests.get(url, timeout=10)
                print(f"{url}: Status Code: {response.status_code}, Length: {len(response.content)} bytes")
            except requests.exceptions.MissingSchema:
                print(f"{url}: Error - Invalid URL format")
            except requests.exceptions.ConnectionError:
                print(f"{url}: Error - Connection failed")
            except requests.exceptions.Timeout:
                print(f"{url}: Error - Request timed out")
            except requests.exceptions.RequestException as e:
                print(f"{url}: Error - {str(e)}")
    except Exception as e:
        print(f"Error processing file: {str(e)}", file=sys.stderr)
        sys.exit(1)

if __name__ == '__main__':
    fetch_urls()

