use serde::{Deserialize, Serialize};
use std::collections::HashSet;
use tide::{Body, Request, Response, StatusCode};

#[derive(Deserialize)]
struct ProductCodeRequest {
    codes: Vec<String>,
}

#[derive(Serialize)]
struct ProductCodeResponse {
    valid_codes: Vec<String>,
    invalid_codes: Vec<String>,
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let mut app = tide::new();
    app.at("/validate-codes").post(validate_product_codes);
    app.listen("127.0.0.1:8080").await?;
    Ok(())
}

async fn validate_product_codes(mut req: Request<()>) -> tide::Result {
    // Define valid product codes
    let valid_product_codes: HashSet<String> = vec![
        "PRD001".to_string(),
        "PRD002".to_string(),
        "PRD003".to_string(),
        "PRD004".to_string(),
        "PRD005".to_string(),
    ]
    .into_iter()
    .collect();

    // Parse request body
    let result = req.body_json::<ProductCodeRequest>().await;

    match result {
        Ok(product_request) => {
            let mut valid_codes = Vec::new();
            let mut invalid_codes = Vec::new();

            // Check each code against the valid codes list
            for code in product_request.codes {
                if valid_product_codes.contains(&code) {
                    valid_codes.push(code);
                } else {
                    invalid_codes.push(code);
                }
            }

            // Create response
            let response = ProductCodeResponse {
                valid_codes,
                invalid_codes,
            };

            // Return JSON response
            let mut resp = Response::new(StatusCode::Ok);
            resp.set_body(Body::from_json(&response)?);
            Ok(resp)
        }
        Err(_) => {
            // Handle malformed JSON error
            let mut resp = Response::new(StatusCode::BadRequest);
            resp.set_body(Body::from_json(&serde_json::json!({
                "error": "Malformed JSON in request body"
            }))?);
            Ok(resp)
        }
    }
}

use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Method, Request, Response, Server, StatusCode};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::convert::Infallible;
use std::fs;
use std::net::SocketAddr;
use std::path::Path;
use std::sync::{Arc, Mutex};

#[derive(Serialize, Deserialize, Clone, Debug)]
struct Employee {
    id: u32,
    name: String,
    position: String,
    department: String,
    salary: u32,
}

type EmployeeDb = Arc<Mutex<HashMap<u32, Employee>>>;

const DATA_FILE: &str = "employees.json";

async fn load_data() -> Result<EmployeeDb, String> {
    let db = Arc::new(Mutex::new(HashMap::new()));

    // Check if file exists
    if !Path::new(DATA_FILE).exists() {
        return Err(format!("Data file '{}' not found", DATA_FILE));
    }

    // Read and parse data file
    match fs::read_to_string(DATA_FILE) {
        Ok(contents) => {
            match serde_json::from_str::<Vec<Employee>>(&contents) {
                Ok(employees) => {
                    let mut db_guard = db.lock().unwrap();
                    for employee in employees {
                        db_guard.insert(employee.id, employee);
                    }
                    Ok(db)
                },
                Err(e) => Err(format!("Failed to parse employee data: {}", e))
            }
        },
        Err(e) => Err(format!("Failed to read data file: {}", e))
    }
}

async fn handle_request(req: Request<Body>, db: EmployeeDb) -> Result<Response<Body>, Infallible> {
    match (req.method(), req.uri().path()) {
        (&Method::GET, "/employees") => {
            // Return all employees
            let db_guard = db.lock().unwrap();
            let employees: Vec<&Employee> = db_guard.values().collect();

            match serde_json::to_string(&employees) {
                Ok(json) => {
                    let response = Response::builder()
                        .status(StatusCode::OK)
                        .header("Content-Type", "application/json")
                        .body(Body::from(json))
                        .unwrap();
                    Ok(response)
                },
                Err(_) => {
                    let response = Response::builder()
                        .status(StatusCode::INTERNAL_SERVER_ERROR)
                        .body(Body::from("Failed to serialize employee data"))
                        .unwrap();
                    Ok(response)
                }
            }
        },
        (&Method::GET, path) if path.starts_with("/employee/") => {
            // Extract employee ID from path
            let id: u32 = match path.trim_start_matches("/employee/").parse() {
                Ok(id) => id,
                Err(_) => {
                    return Ok(Response::builder()
                        .status(StatusCode::BAD_REQUEST)
                        .body(Body::from("Invalid employee ID"))
                        .unwrap());
                }
            };

            // Find employee by ID
            let db_guard = db.lock().unwrap();
            match db_guard.get(&id) {
                Some(employee) => {
                    match serde_json::to_string(employee) {
                        Ok(json) => {
                            let response = Response::builder()
                                .status(StatusCode::OK)
                                .header("Content-Type", "application/json")
                                .body(Body::from(json))
                                .unwrap();
                            Ok(response)
                        },
                        Err(_) => {
                            let response = Response::builder()
                                .status(StatusCode::INTERNAL_SERVER_ERROR)
                                .body(Body::from("Failed to serialize employee data"))
                                .unwrap();
                            Ok(response)
                        }
                    }
                },
                None => {
                    let response = Response::builder()
                        .status(StatusCode::NOT_FOUND)
                        .body(Body::from(format!("Employee with ID {} not found", id)))
                        .unwrap();
                    Ok(response)
                }
            }
        },
        // Return 404 for all other routes
        _ => {
            let response = Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body(Body::from("Not found"))
                .unwrap();
            Ok(response)
        }
    }
}

#[tokio::main]
async fn main() {
    // Load employee data
    let db = match load_data().await {
        Ok(db) => db,
        Err(err) => {
            eprintln!("Failed to load employee data: {}", err);
            std::process::exit(1);
        }
    };

    println!("Successfully loaded employee data");

    // Define server address
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));

    // Create service
    let db_clone = db.clone();
    let make_svc = make_service_fn(move |_conn| {
        let db = db_clone.clone();
        async move {
            Ok::<_, Infallible>(service_fn(move |req| {
                handle_request(req, db.clone())
            }))
        }
    });

    // Create and start server
    let server = Server::bind(&addr).serve(make_svc);
    println!("Server running on http://{}", addr);

    // Run the server
    if let Err(e) = server.await {
        eprintln!("Server error: {}", e);
    }
}

