use tokio::net::{TcpListener, TcpStream};
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use serde::{Deserialize, Serialize};
use std::error::Error;

#[derive(Deserialize)]
struct Request {
    numbers: Vec<i32>,
}

#[derive(Serialize)]
struct Response {
    sorted: Vec<i32>,
}

#[derive(Serialize)]
struct ErrorResponse {
    error: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    println!("Server listening on 127.0.0.1:8080");

    loop {
        let (socket, _) = listener.accept().await?;
        tokio::spawn(async move {
            if let Err(e) = handle_connection(socket).await {
                eprintln!("Error handling connection: {}", e);
            }
        });
    }
}

async fn handle_connection(mut socket: TcpStream) -> Result<(), Box<dyn Error>> {
    let mut buffer = Vec::new();

    // Read HTTP headers
    let mut headers = [0; 1024];
    let n = socket.read(&mut headers).await?;

    // Find Content-Length
    let headers_str = String::from_utf8_lossy(&headers[..n]);
    let content_length = parse_content_length(&headers_str)?;

    // Read HTTP body
    let mut body = vec![0; content_length];
    socket.read_exact(&mut body).await?;

    // Process the request
    let response = match serde_json::from_slice::<Request>(&body) {
        Ok(request) => {
            let mut numbers = request.numbers;
            numbers.sort();

            let response = Response { sorted: numbers };
            serde_json::to_vec(&response)?
        },
        Err(e) => {
            let error_response = ErrorResponse { error: e.to_string() };
            serde_json::to_vec(&error_response)?
        }
    };

    // Write HTTP response
    let response_headers = format!(
        "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n",
        response.len()
    );

    socket.write_all(response_headers.as_bytes()).await?;
    socket.write_all(&response).await?;

    Ok(())
}

fn parse_content_length(headers: &str) -> Result<usize, Box<dyn Error>> {
    for line in headers.lines() {
        if line.to_lowercase().starts_with("content-length:") {
            let parts: Vec<&str> = line.splitn(2, ':').collect();
            if parts.len() == 2 {
                return Ok(parts[1].trim().parse()?);
            }
        }
    }
    Err("Content-Length header not found".into())
}

