// Define the UserSettings type
const UserSettingsCodec = t.type({
  theme: t.string,
  notifications: t.boolean,
  language: t.string,
  fontSize: t.number,
  autoSave: t.boolean,
});

type UserSettings = t.TypeOf<typeof UserSettingsCodec>;

// Path to the settings file
const settingsFilePath = path.join(__dirname, 'userSettings.json');

// Read settings from file
const readSettingsFile = (): TE.TaskEither<Error, string> =>
  TE.tryCatch(
    () => T.of(fs.readFileSync(settingsFilePath, 'utf8'))(),
    (reason) => new Error(`Failed to read settings file: ${String(reason)}`)
  );

// Parse JSON string to UserSettings
const parseSettings = (jsonStr: string): E.Either<Error, UserSettings> =>
  pipe(
    J.parse(jsonStr),
    E.mapLeft(err => new Error(`Invalid JSON format: ${String(err)}`)),
    E.chain(json => 
      pipe(
        UserSettingsCodec.decode(json),
        E.mapLeft(errors => new Error(`Invalid settings format: ${JSON.stringify(errors)}}`))
      )
    )
  );

// Write settings to file
const writeSettingsFile = (settings: UserSettings): TE.TaskEither<Error, void> =>
  TE.tryCatch(
    () => T.of(fs.writeFileSync(settingsFilePath, JSON.stringify(settings, null, 2), 'utf8'))(),
    (reason) => new Error(`Failed to write settings file: ${String(reason)}`)
  );

// Get user settings
const getUserSettings = (): TE.TaskEither<Error, UserSettings> =>
  pipe(
    readSettingsFile(),
    TE.chain(jsonStr => TE.fromEither(parseSettings(jsonStr)))
  );

// Update user settings (immutable)
const updateUserSettings = (
  currentSettings: UserSettings,
  updates: Partial<UserSettings>
): UserSettings => ({
  ...currentSettings,
  ...updates,
});

// Service interface
export interface UserConfigService {
  getSettings(): TE.TaskEither<Error, UserSettings>;
  updateSettings(updates: Partial<UserSettings>): TE.TaskEither<Error, UserSettings>;
}

// Service implementation
export const createUserConfigService = (): UserConfigService => {
  return {
    getSettings: getUserSettings,

    updateSettings(updates: Partial<UserSettings>): TE.TaskEither<Error, UserSettings> {
      return pipe(
        getUserSettings(),
        TE.map(currentSettings => updateUserSettings(currentSettings, updates)),
        TE.chain(newSettings => 
          pipe(
            writeSettingsFile(newSettings),
            TE.map(() => newSettings)
          )
        )
      );
    }
  };
};

