use diesel::prelude::*;
use crate::database::{DbResult, establish_connection};
use crate::models::{Book, NewBook, UpdateBook};
use crate::schema::books::dsl::*;

pub fn create_book(new_title: &str, new_author: &str, new_year: i32, new_quantity: i32) -> DbResult<Book> {
    let mut conn = establish_connection()?;

    let new_book = NewBook {
        title: new_title,
        author: new_author,
        year_published: new_year,
        quantity: new_quantity,
    };

    diesel::insert_into(books)
        .values(&new_book)
        .returning(Book::as_returning())
        .get_result(&mut conn)
        .map_err(|e| e.into())
}

pub fn get_all_books() -> DbResult<Vec<Book>> {
    let mut conn = establish_connection()?;

    books
        .select(Book::as_select())
        .load(&mut conn)
        .map_err(|e| e.into())
}

pub fn get_book_by_id(book_id: i32) -> DbResult<Book> {
    let mut conn = establish_connection()?;

    books
        .find(book_id)
        .select(Book::as_select())
        .first(&mut conn)
        .map_err(|e| e.into())
}

pub fn search_books_by_title(search_title: &str) -> DbResult<Vec<Book>> {
    let mut conn = establish_connection()?;

    books
        .filter(title.ilike(format!("%{}%", search_title)))
        .select(Book::as_select())
        .load(&mut conn)
        .map_err(|e| e.into())
}

pub fn search_books_by_author(search_author: &str) -> DbResult<Vec<Book>> {
    let mut conn = establish_connection()?;

    books
        .filter(author.ilike(format!("%{}%", search_author)))
        .select(Book::as_select())
        .load(&mut conn)
        .map_err(|e| e.into())
}

pub fn update_book(book_id: i32, updates: UpdateBook) -> DbResult<Book> {
    let mut conn = establish_connection()?;

    diesel::update(books.find(book_id))
        .set(&updates)
        .returning(Book::as_returning())
        .get_result(&mut conn)
        .map_err(|e| e.into())
}

pub fn delete_book(book_id: i32) -> DbResult<usize> {
    let mut conn = establish_connection()?;

    diesel::delete(books.find(book_id))
        .execute(&mut conn)
        .map_err(|e| e.into())
}

