        year_published: None,
        quantity: None,
    };

    // Get new title
    print!("Title [{}]: ", existing_book.title);
    io::stdout().flush()?;
    let mut input = String::new();
    io::stdin().read_line(&mut input)?;
    let new_title = input.trim();
    if !new_title.is_empty() {
        updates.title = Some(new_title.to_string());
    }

    // Get new author
    print!("Author [{}]: ", existing_book.author);
    io::stdout().flush()?;
    input.clear();
    io::stdin().read_line(&mut input)?;
    let new_author = input.trim();
    if !new_author.is_empty() {
        updates.author = Some(new_author.to_string());
    }

    // Get new year
    print!("Year [{}]: ", existing_book.year_published);
    io::stdout().flush()?;
    input.clear();
    io::stdin().read_line(&mut input)?;
    let new_year = input.trim();
    if !new_year.is_empty() {
        let year: i32 = new_year.parse()
            .map_err(|_| "Invalid year format")?;
        if year < 1000 || year > 2100 {
            return Err("Year must be between 1000 and 2100".into());
        }
        updates.year_published = Some(year);
    }

    // Get new quantity
    print!("Quantity [{}]: ", existing_book.quantity);
    io::stdout().flush()?;
    input.clear();
    io::stdin().read_line(&mut input)?;
    let new_quantity = input.trim();
    if !new_quantity.is_empty() {
        let quantity: i32 = new_quantity.parse()
            .map_err(|_| "Invalid quantity format")?;
        if quantity < 0 {
            return Err("Quantity cannot be negative".into());
        }
        updates.quantity = Some(quantity);
    }

    let updated_book = operations::update_book(id, updates)?;
    println!("\n✅ Successfully updated book:");
    print_book(&updated_book);

    Ok(())
}

fn handle_delete_book(id: i32) -> Result<(), Box<dyn std::error::Error>> {
