// Store active users in each room
const roomUsers = {};

io.on('connection', (socket) => {
  let currentUser = null;
  let currentRoom = null;

  // Handle user joining a room
  socket.on('joinRoom', ({ username, room }) => {
    currentUser = username;
    currentRoom = room;

    socket.join(room);

    // Initialize room if it doesn't exist
    if (!roomUsers[room]) {
      roomUsers[room] = [];
    }

    roomUsers[room].push(username);

    // Send welcome message to the user
    socket.emit('message', {
      username: 'System',
      text: `Welcome to the chat room ${room}!`,
      timestamp: new Date().toLocaleTimeString()
    });

    // Broadcast to others that a new user has joined
    socket.broadcast.to(room).emit('message', {
      username: 'System',
      text: `${username} has joined the chat`,
      timestamp: new Date().toLocaleTimeString()
    });

    // Send updated room users list
    io.to(room).emit('roomUsers', {
      room: room,
      users: roomUsers[room]
    });
  });

  // Handle chat messages
  socket.on('chatMessage', (message) => {
    if (currentRoom) {
      io.to(currentRoom).emit('message', {
        username: currentUser,
        text: message,
        timestamp: new Date().toLocaleTimeString()
      });
    }
  });

  // Handle user disconnection
  socket.on('disconnect', () => {
    if (currentUser && currentRoom) {
      // Remove user from room
      if (roomUsers[currentRoom]) {
        roomUsers[currentRoom] = roomUsers[currentRoom].filter(user => user !== currentUser);

        // Delete room if empty
        if (roomUsers[currentRoom].length === 0) {
          delete roomUsers[currentRoom];
        } else {
          // Notify remaining users
          io.to(currentRoom).emit('message', {
            username: 'System',
            text: `${currentUser} has left the chat`,
            timestamp: new Date().toLocaleTimeString()
          });

          // Send updated room users list
          io.to(currentRoom).emit('roomUsers', {
            room: currentRoom,
            users: roomUsers[currentRoom]
          });
        }
      }

      socket.leave(currentRoom);
    }
  });
});

