use std::collections::HashMap;
use std::error::Error;
use std::fs::File;
use std::io::Read;
use serde::Deserialize;
use reqwest;

#[derive(Debug, Deserialize)]
struct Config {
    crypto_ids: Vec<String>,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    // Read configuration file
    let mut file = match File::open("config.json") {
        Ok(file) => file,
        Err(e) => {
            eprintln!("Failed to open configuration file: {}", e);
            return Err(Box::new(e));
        }
    };

    let mut contents = String::new();
    if let Err(e) = file.read_to_string(&mut contents) {
        eprintln!("Failed to read configuration file: {}", e);
        return Err(Box::new(e));
    }

    let config: Config = match serde_json::from_str(&contents) {
        Ok(config) => config,
        Err(e) => {
            eprintln!("Failed to parse configuration file: {}", e);
            return Err(Box::new(e));
        }
    };

    // Create HTTP client
    let client = reqwest::Client::new();

    // Process each cryptocurrency ID
    for crypto_id in config.crypto_ids {
        let url = format!("https://api.coingecko.com/api/v3/simple/price?ids={}&vs_currencies=usd", crypto_id);

        match client.get(&url).send().await {
            Ok(response) => {
                if response.status().is_success() {
                    match response.json::<HashMap<String, HashMap<String, f64>>>().await {
                        Ok(data) => {
                            match data.get(&crypto_id) {
                                Some(price_data) => {
                                    match price_data.get("usd") {
                                        Some(price) => {
                                            println!("{}: ${:.2}", crypto_id, price);
                                        },
                                        None => {
                                            eprintln!("No USD price found for {}", crypto_id);
                                        }
                                    }
                                },
                                None => {
                                    eprintln!("No data returned for cryptocurrency ID: {}", crypto_id);
                                }
                            }
                        },
                        Err(e) => {
                            eprintln!("Failed to parse response for {}: {}", crypto_id, e);
                        }
                    }
                } else if response.status().as_u16() == 429 {
                    eprintln!("Rate limit exceeded for {}", crypto_id);
                } else if response.status().as_u16() == 404 {
                    eprintln!("Cryptocurrency ID not found: {}", crypto_id);
                } else {
                    eprintln!("API request failed for {}: HTTP {}", crypto_id, response.status());
                }
            },
            Err(e) => {
                eprintln!("Connection error for {}: {}", crypto_id, e);
            }
        }
    }

    Ok(())
}

const got = require('got');
const fs = require('fs');

// Read the username from a JSON file
const readUserConfig = () => {
  try {
    const data = fs.readFileSync('user-config.json', 'utf8');
    const config = JSON.parse(data);
    if (!config.username) {
      throw new Error('Username not found in config file');
    }
    return config.username;
  } catch (error) {
    console.error('Error reading config file:', error.message);
    process.exit(1);
  }
};

// Fetch repositories for a given username
const fetchRepositories = async (username) => {
  try {
    const response = await got(`https://api.github.com/users/${username}/repos`, {
      responseType: 'json',
      headers: {
        'User-Agent': 'Node-Repository-Lister'
      }
    });

    return response.body;
  } catch (error) {
    if (error.response) {
      if (error.response.statusCode === 404) {
        throw new Error(`User '${username}' not found`);
      } else {
        throw new Error(`GitHub API error: ${error.response.statusCode} - ${error.response.statusMessage}`);
      }
    } else {
      throw new Error(`Network error: ${error.message}`);
    }
  }
};

// Main function
const main = async () => {
  try {
    const username = readUserConfig();
    console.log(`Fetching repositories for GitHub user: ${username}\n`);

    const repositories = await fetchRepositories(username);

    if (repositories.length === 0) {
      console.log(`No repositories found for user: ${username}`);
      return;
    }

    console.log(`Found ${repositories.length} repositories:\n`);

    repositories.forEach((repo, index) => {
      console.log(`${index + 1}. ${repo.name}`);
      if (repo.description) {
        console.log(`   Description: ${repo.description}`);
