import { injectable, inject, container } from "tsyringe";

// Custom error handling mechanism
class TaskError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "TaskError";
  }
}

// Task interface
interface Task {
  id: string;
  name: string;
  execute: () => Promise<void>;
}

// TaskService class for managing tasks
@injectable()
class TaskService {
  private tasks: Map<string, Task> = new Map();

  registerTask(task: Task): void {
    this.tasks.set(task.id, task);
  }

  getTask(id: string): Task | undefined {
    return this.tasks.get(id);
  }

  getAllTasks(): Task[] {
    return Array.from(this.tasks.values());
  }
}

// Scheduler class that depends on TaskService
@injectable()
class Scheduler {
  constructor(@inject(TaskService) private taskService: TaskService) {}

  async initiateTask(taskId: string): Promise<void> {
    const task = this.taskService.getTask(taskId);

    if (!task) {
      throw new TaskError(`Task with ID ${taskId} not found`);
    }

    try {
      console.log(`[${new Date().toISOString()}] Starting task: ${task.name}`);
      const startTime = Date.now();

      await task.execute();

      const endTime = Date.now();
      console.log(`[${new Date().toISOString()}] Completed task: ${task.name} in ${endTime - startTime}ms`);
    } catch (error) {
      this.handleError(task, error instanceof Error ? error : new Error(String(error)));
    }
  }

  async initiateAllTasks(): Promise<void> {
    const tasks = this.taskService.getAllTasks();

    for (const task of tasks) {
      await this.initiateTask(task.id);
    }
  }

  private handleError(task: Task, error: Error): void {
    const errorMessage = `Error executing task ${task.name}: ${error.message}`;
    console.error(`[${new Date().toISOString()}] ${errorMessage}`);

    // Additional error handling logic could be implemented here
    // e.g., sending error notifications, retrying tasks, etc.
  }
}

// Register the classes with tsyringe
container.registerSingleton(TaskService);
container.registerSingleton(Scheduler);

// Example usage
async function main() {
  // Resolve dependencies
  const taskService = container.resolve(TaskService);
  const scheduler = container.resolve(Scheduler);

  // Register some sample tasks
  taskService.registerTask({
    id: "task1",
