import csv
import requests
from selectolax.parser import HTMLParser
from urllib.parse import urlparse
import logging
from requests.exceptions import RequestException

def crawl_urls(urls):
    results = []

    for url in urls:
        try:
            logging.info(f"Crawling: {url}")
            response = requests.get(url, timeout=10)
            response.raise_for_status()

            html = response.text
            parser = HTMLParser(html)

            links = []
            for tag in parser.css('a'):
                href = tag.attributes.get('href')
                if href:
                    links.append(href)

            results.append({
                'source_url': url,
                'links': links
            })

        except RequestException as e:
            logging.error(f"Error crawling {url}: {e}")
            results.append({
                'source_url': url,
                'links': []
            })
        except Exception as e:
            logging.error(f"Unexpected error with {url}: {e}")
            results.append({
                'source_url': url,
                'links': []
            })

    return results

def save_to_csv(results, output_file):
    with open(output_file, 'w', newline='', encoding='utf-8') as csvfile:
        writer = csv.writer(csvfile)
        writer.writerow(['source_url', 'found_link'])

        for result in results:
            source_url = result['source_url']
            for link in result['links']:
                writer.writerow([source_url, link])

def main():
    logging.basicConfig(level=logging.INFO, 
                        format='%(asctime)s - %(levelname)s - %(message)s')

    # List of URLs to crawl
    urls = [
        "https://example.com",
        "https://python.org",
        "https://github.com"
    ]

    results = crawl_urls(urls)
    save_to_csv(results, "crawled_links.csv")
    logging.info("Crawling complete. Results saved to crawled_links.csv")

if __name__ == "__main__":
    main()

