func main() {
	// Initialize client
	client, err := ent.Open("sqlite3", "file:books.db?mode=memory&cache=shared&_fk=1")
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer client.Close()

	// Create schema
	if err := client.Schema.Create(context.Background()); err != nil {
		log.Fatalf("Failed to create schema: %v", err)
	}

	ctx := context.Background()

	// Create books
	createBook(ctx, client, "The Go Programming Language", "Alan Donovan & Brian Kernighan", 2015)
	createBook(ctx, client, "Clean Code", "Robert C. Martin", 2008)
	createBook(ctx, client, "Refactoring", "Martin Fowler", 1999)
	createBook(ctx, client, "Patterns of Enterprise Application Architecture", "Martin Fowler", 2002)

	// Read all books
	books, err := getAllBooks(ctx, client)
	if err != nil {
		log.Fatalf("Failed to query books: %v", err)
	}
	fmt.Println("All books:")
	for _, b := range books {
		fmt.Printf("- %s by %s (%d)\n", b.Title, b.Author, b.PublicationYear)
	}

	// Get books by author
	fowlerBooks, err := getBooksByAuthor(ctx, client, "Martin Fowler")
	if err != nil {
		log.Fatalf("Failed to query books by author: %v", err)
	}
	fmt.Println("\nBooks by Martin Fowler:")
	for _, b := range fowlerBooks {
		fmt.Printf("- %s (%d)\n", b.Title, b.PublicationYear)
	}

	// Update book's publication year
	if len(books) > 0 {
		updateBookPublicationYear(ctx, client, books[0].ID, 2016)
		book, err := getBookByID(ctx, client, books[0].ID)
		if err != nil {
			log.Fatalf("Failed to get updated book: %v", err)
		}
		fmt.Printf("\nUpdated book: %s by %s (%d)\n", book.Title, book.Author, book.PublicationYear)
	}

	// Delete a book
	if len(books) > 0 {
		if err := deleteBook(ctx, client, books[len(books)-1].ID); err != nil {
			log.Fatalf("Failed to delete book: %v", err)
		}
		fmt.Println("\nDeleted the last book")
	}

	// Final list of books
	books, err = getAllBooks(ctx, client)
	if err != nil {
		log.Fatalf("Failed to query books: %v", err)
	}
	fmt.Println("\nRemaining books:")
	for _, b := range books {
		fmt.Printf("- %s by %s (%d)\n", b.Title, b.Author, b.PublicationYear)
	}
}

// CreateBook creates a new book entity in the database
func createBook(ctx context.Context, client *ent.Client, title, author string, publicationYear int) (*ent.Book, error) {
	book, err := client.Book.
		Create().
		SetTitle(title).
		SetAuthor(author).
		SetPublicationYear(publicationYear).
		SetCreatedAt(time.Now()).
		Save(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed creating book: %w", err)
	}
	return book, nil
}

// GetAllBooks retrieves all books from the database
func getAllBooks(ctx context.Context, client *ent.Client) ([]*ent.Book, error) {
	books, err := client.Book.
		Query().
		Order(ent.Asc(book.FieldTitle)).
		All(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed querying books: %w", err)
	}
	return books, nil
}

// GetBookByID retrieves a book by its ID
func getBookByID(ctx context.Context, client *ent.Client, id int) (*ent.Book, error) {
	book, err := client.Book.
		Get(ctx, id)
	if err != nil {
		return nil, fmt.Errorf("failed querying book: %w", err)
	}
	return book, nil
}

// GetBooksByAuthor retrieves all books by a specific author
func getBooksByAuthor(ctx context.Context, client *ent.Client, author string) ([]*ent.Book, error) {
	books, err := client.Book.
		Query().
		Where(book.AuthorEQ(author)).
		Order(ent.Asc(book.FieldPublicationYear)).
		All(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed querying books by author: %w", err)
	}
	return books, nil
}

// UpdateBookPublicationYear updates the publication year of a book
func updateBookPublicationYear(ctx context.Context, client *ent.Client, id int, year int) (*ent.Book, error) {
	book, err := client.Book.
		UpdateOneID(id).
		SetPublicationYear(year).
		SetUpdatedAt(time.Now()).
		Save(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed updating book: %w", err)
	}
	return book, nil
}

// DeleteBook deletes a book by its ID
func deleteBook(ctx context.Context, client *ent.Client, id int) error {
	err := client.Book.
		DeleteOneID(id).
		Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed deleting book: %w", err)
	}
	return nil
}

