package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/urfave/cli/v2"
)

type Record struct {
	Name      string    `json:"name"`
	Timestamp time.Time `json:"timestamp"`
}

func main() {
	app := &cli.App{
		Name:  "jsonProcessor",
		Usage: "Process JSON files in a directory",
		Flags: []cli.Flag{
			&cli.StringFlag{
				Name:     "dir",
				Aliases:  []string{"d"},
				Usage:    "Directory containing JSON files",
				Required: true,
			},
			&cli.StringFlag{
				Name:    "after",
				Aliases: []string{"a"},
				Usage:   "Filter records after this time (format: 2006-01-02T15:04:05Z)",
			},
		},
		Action: func(c *cli.Context) error {
			dirPath := c.String("dir")
			afterTimeStr := c.String("after")

			var afterTime time.Time
			var err error
			if afterTimeStr != "" {
				afterTime, err = time.Parse(time.RFC3339, afterTimeStr)
				if err != nil {
					return fmt.Errorf("invalid time format: %v", err)
				}
			}

			names, err := processDirectory(dirPath, afterTime, afterTimeStr != "")
			if err != nil {
				return err
			}

			for _, name := range names {
				fmt.Println(name)
			}

			return nil
		},
	}

	err := app.Run(os.Args)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
}

func processDirectory(dirPath string, afterTime time.Time, filterByTime bool) ([]string, error) {
	// Check if directory exists
	info, err := os.Stat(dirPath)
	if err != nil {
		return nil, fmt.Errorf("directory error: %v", err)
	}
	if !info.IsDir() {
		return nil, fmt.Errorf("%s is not a directory", dirPath)
	}

	// Read directory contents
	files, err := ioutil.ReadDir(dirPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read directory: %v", err)
	}

	var allNames []string
	for _, file := range files {
		if filepath.Ext(file.Name()) == ".json" {
			filePath := filepath.Join(dirPath, file.Name())
			names, err := processFile(filePath, afterTime, filterByTime)
			if err != nil {
				fmt.Fprintf(os.Stderr, "Error processing %s: %v\n", file.Name(), err)
				continue
			}
			allNames = append(allNames, names...)
		}
	}

	// Sort names alphabetically
	sort.Strings(allNames)
	return allNames, nil
}

func processFile(filePath string, afterTime time.Time, filterByTime bool) ([]string, error) {
	// Read file
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to read file: %v", err)
	}

	// Parse JSON
	var records []Record
	err = json.Unmarshal(data, &records)
	if err != nil {
		return nil, fmt.Errorf("failed to parse JSON: %v", err)
	}

	// Filter and extract names
	var names []string
	for _, record := range records {
		if !filterByTime || record.Timestamp.After(afterTime) {
			names = append(names, record.Name)
		}
	}

	return names, nil
}

