// In-memory storage
const books: Map<string, Book> = new Map();

export class BookRepository {
  public async getAll(): Promise<Book[]> {
    return Array.from(books.values());
  }

  public async getById(id: string): Promise<Book | null> {
    const book = books.get(id);
    return book || null;
  }

  public async create(book: Omit<Book, 'id'>): Promise<Book> {
    const id = Math.random().toString(36).substring(2, 15);
    const newBook: Book = { ...book, id };
    books.set(id, newBook);
    return newBook;
  }

  public async update(id: string, book: Partial<Book>): Promise<Book | null> {
    const existingBook = books.get(id);
    if (!existingBook) {
      return null;
    }
    const updatedBook = { ...existingBook, ...book };
    books.set(id, updatedBook);
    return updatedBook;
  }

  public async delete(id: string): Promise<boolean> {
    return books.delete(id);
  }
}

