import { Body, Controller, Delete, Get, Path, Post, Put, Route, Response, Tags } from 'tsoa';
import { Book } from '../models/Book';
import { BookRepository } from '../repositories/BookRepository';

@Route('books')
@Tags('Books')
export class BookController extends Controller {
  private repository: BookRepository = new BookRepository();

  @Get()
  public async getBooks(): Promise<Book[]> {
    return this.repository.getAll();
  }

  @Response(404, 'Book not found')
  @Get('{id}')
  public async getBook(@Path() id: string): Promise<Book> {
    const book = await this.repository.getById(id);
    if (!book) {
      this.setStatus(404);
      throw new Error('Book not found');
    }
    return book;
  }

  @Response(400, 'Invalid input')
  @Post()
  public async createBook(@Body() requestBody: Omit<Book, 'id'>): Promise<Book> {
    if (!requestBody.title || !requestBody.isbn) {
      this.setStatus(400);
      throw new Error('Title and ISBN are required');
    }
    return this.repository.create(requestBody);
  }

  @Response(404, 'Book not found')
  @Response(400, 'Invalid input')
  @Put('{id}')
  public async updateBook(@Path() id: string, @Body() requestBody: Partial<Book>): Promise<Book> {
    if (Object.keys(requestBody).length === 0) {
      this.setStatus(400);
      throw new Error('No update fields provided');
    }

    const updatedBook = await this.repository.update(id, requestBody);
    if (!updatedBook) {
      this.setStatus(404);
      throw new Error('Book not found');
    }
    return updatedBook;
  }

  @Response(404, 'Book not found')
  @Delete('{id}')
  public async deleteBook(@Path() id: string): Promise<void> {
    const deleted = await this.repository.delete(id);
    if (!deleted) {
      this.setStatus(404);
      throw new Error('Book not found');
    }
    this.setStatus(204);
  }
}

