package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
	"time"

	"github.com/go-co-op/gocron"
)

func main() {
	scheduler := gocron.NewScheduler(time.UTC)

	_, err := scheduler.Every(10).Minutes().Do(checkDiskSpace)
	if err != nil {
		fmt.Printf("Failed to schedule disk space check: %v\n", err)
		return
	}

	scheduler.StartBlocking()
}

func checkDiskSpace() {
	// Get disk usage using df command
	cmd := exec.Command("df", "-h", "/")
	output, err := cmd.Output()
	if err != nil {
		logError("Failed to execute df command: " + err.Error())
		return
	}

	// Parse the output to get disk usage percentage
	lines := strings.Split(string(output), "\n")
	if len(lines) < 2 {
		logError("Unexpected output format from df command")
		return
	}

	fields := strings.Fields(lines[1])
	if len(fields) < 5 {
		logError("Unable to parse disk usage information")
		return
	}

	usagePercentage := fields[4]
	timestamp := time.Now().Format("2006-01-02 15:04:05")
	logMessage := fmt.Sprintf("%s - Disk usage: %s\n", timestamp, usagePercentage)

	// Write to log file
	file, err := os.OpenFile("disk_usage.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		logError("Failed to open log file: " + err.Error())
		return
	}
	defer file.Close()

	if _, err := file.WriteString(logMessage); err != nil {
		logError("Failed to write to log file: " + err.Error())
		return
	}
}

func logError(message string) {
	errorLog, err := os.OpenFile("disk_usage.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		fmt.Printf("Failed to open error log file: %v\n", err)
		return
	}
	defer errorLog.Close()

	timestamp := time.Now().Format("2006-01-02 15:04:05")
	errorMessage := fmt.Sprintf("%s - ERROR: %s\n", timestamp, message)

	if _, err := errorLog.WriteString(errorMessage); err != nil {
		fmt.Printf("Failed to write error to log file: %v\n", err)
	}
}

use std::fs::{File, self};
use std::io::{Read, Write};
use std::error::Error;
use serde::{Deserialize, Serialize};

#[derive(Debug, Deserialize)]
struct Student {
    name: String,
    age: u32,
    gpa: f32,
}

#[derive(Debug, Serialize)]
struct Result {
    average_gpa: f32,
}

fn main() -> Result<(), Box<dyn Error>> {
    // Read the JSON file
    let mut file = match File::open("students.json") {
        Ok(file) => file,
        Err(err) => {
            eprintln!("Error opening file: {}", err);
            return Err(err.into());
        }
    };

    let mut contents = String::new();
    if let Err(err) = file.read_to_string(&mut contents) {
        eprintln!("Error reading file: {}", err);
        return Err(err.into());
    }

    // Deserialize the JSON content
    let students: Vec<Student> = match serde_json::from_str(&contents) {
        Ok(students) => students,
        Err(err) => {
            eprintln!("Error deserializing JSON: {}", err);
            return Err(err.into());
        }
    };

    // Calculate the average GPA
    if students.is_empty() {
        eprintln!("No students found in the file");
        return Err("No students found".into());
    }

    let total_gpa: f32 = students.iter().map(|s| s.gpa).sum();
    let average_gpa = total_gpa / students.len() as f32;

    // Serialize the result back to JSON
    let result = Result { average_gpa };
    let output = match serde_json::to_string_pretty(&result) {
        Ok(output) => output,
        Err(err) => {
            eprintln!("Error serializing result: {}", err);
            return Err(err.into());
        }
    };

    // Write the result to a file
    if let Err(err) = fs::write("result.json", output) {
        eprintln!("Error writing result file: {}", err);
        return Err(err.into());
    }

    Ok(())
}

const yup = require('yup');
const readline = require('readline');

// Create readline interface
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

// Define validation schema
const userSchema = yup.object({
  email: yup.string()
    .email('Invalid email format')
    .required('Email is required'),
  password: yup.string()
    .min(8, 'Password must be at least 8 characters')
    .matches(/[A-Z]/, 'Password must contain at least one uppercase letter')
    .matches(/[a-z]/, 'Password must contain at least one lowercase letter')
    .matches(/[0-9]/, 'Password must contain at least one number')
    .required('Password is required')
});

// Function to validate user input
async function validateInput(email, password) {
  try {
    await userSchema.validate({ email, password }, { abortEarly: false });
    return { valid: true };
  } catch (error) {
    return {
      valid: false,
      errors: error.inner.map(err => ({
        path: err.path,
        message: err.message
      }))
    };
  }
}

// Get user input
function getUserInput() {
  rl.question('Enter your email: ', (email) => {
    rl.question('Enter your password: ', async (password) => {
      const result = await validateInput(email, password);

      if (result.valid) {
        console.log('Validation successful! User input is valid.');
      } else {
        console.log('Validation failed:');
        result.errors.forEach(err => {
          console.log(`- ${err.path}: ${err.message}`);
        });
      }

      rl.close();
    });
  });
}

