use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use serde::{Deserialize, Serialize};
use sqlx::{postgres::PgPoolOptions, Pool, Postgres};
use argon2::{self, Config};
use rand::Rng;
use std::env;
use std::sync::Arc;

#[derive(Deserialize)]
struct RegisterRequest {
    username: String,
    password: String,
}

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

#[derive(Serialize)]
struct AuthResponse {
    success: bool,
    message: String,
}

struct AppState {
    db_pool: Pool<Postgres>,
}

async fn register(
    req: web::Json<RegisterRequest>,
    state: web::Data<Arc<AppState>>,
) -> impl Responder {
    // Generate salt
    let salt = rand::thread_rng().gen::<[u8; 32]>();

    // Hash password
    let config = Config::default();
    let hash = match argon2::hash_encoded(req.password.as_bytes(), &salt, &config) {
        Ok(hash) => hash,
        Err(_) => {
            return HttpResponse::InternalServerError().json(AuthResponse {
                success: false,
                message: "Failed to hash password".to_string(),
            });
        }
    };

    // Insert user into database
    let result = sqlx::query!(
        "INSERT INTO users (username, password_hash) VALUES ($1, $2)",
        req.username,
        hash
    )
    .execute(&state.db_pool)
    .await;

    match result {
        Ok(_) => HttpResponse::Ok().json(AuthResponse {
            success: true,
            message: "User registered successfully".to_string(),
        }),
        Err(e) => {
            if e.to_string().contains("duplicate") {
                HttpResponse::Conflict().json(AuthResponse {
                    success: false,
                    message: "Username already exists".to_string(),
                })
            } else {
                HttpResponse::InternalServerError().json(AuthResponse {
                    success: false,
                    message: "Failed to register user".to_string(),
                })
            }
        }
    }
}

async fn login(
    req: web::Json<LoginRequest>,
    state: web::Data<Arc<AppState>>,
) -> impl Responder {
    // Query for user
    let user = sqlx::query!(
        "SELECT password_hash FROM users WHERE username = $1",
        req.username
    )
    .fetch_optional(&state.db_pool)
    .await;

    match user {
        Ok(Some(record)) => {
            // Verify password
            let is_valid = match argon2::verify_encoded(&record.password_hash, req.password.as_bytes()) {
                Ok(valid) => valid,
                Err(_) => {
                    return HttpResponse::InternalServerError().json(AuthResponse {
                        success: false,
                        message: "Error verifying password".to_string(),
                    });
                }
            };

            if is_valid {
                HttpResponse::Ok().json(AuthResponse {
                    success: true,
                    message: "Login successful".to_string(),
                })
            } else {
                HttpResponse::Unauthorized().json(AuthResponse {
                    success: false,
                    message: "Invalid credentials".to_string(),
                })
            }
        },
        Ok(None) => HttpResponse::Unauthorized().json(AuthResponse {
            success: false,
            message: "Invalid credentials".to_string(),
        }),
        Err(_) => HttpResponse::InternalServerError().json(AuthResponse {
            success: false,
            message: "Database error".to_string(),
        }),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // Load environment variables
    dotenv::dotenv().ok();

    // Set up database connection pool
    let database_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let pool = match PgPoolOptions::new()
        .max_connections(5)
        .connect(&database_url)
        .await
    {
        Ok(pool) => pool,
        Err(e) => {
            eprintln!("Failed to connect to database: {}", e);
            std::process::exit(1);
        }
    };

    // Create tables if they don't exist
    if let Err(e) = sqlx::query(
        "CREATE TABLE IF NOT EXISTS users (
            id SERIAL PRIMARY KEY,
            username VARCHAR(255) UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )"
    )
    .execute(&pool)
    .await
    {
        eprintln!("Failed to create users table: {}", e);
        std::process::exit(1);
    }

    let app_state = Arc::new(AppState { db_pool: pool });

    // Start HTTP server
    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(app_state.clone()))
