import asyncio
import aiohttp
import json
from datetime import datetime
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

# List of financial news API endpoints
API_ENDPOINTS = [
    "https://api.example.com/financial-news/v1",
    "https://api.financialnews.org/headlines",
    "https://newsapi.org/v2/top-headlines?category=business",
    "https://market-data-api.com/news"
]

# API keys (replace with actual keys)
API_KEYS = {
    "api.example.com": "your_api_key_1",
    "api.financialnews.org": "your_api_key_2",
    "newsapi.org": "your_api_key_3",
    "market-data-api.com": "your_api_key_4"
}

async def fetch_news(session, url):
    """Fetch news from a single API endpoint"""
    try:
        # Extract domain for API key selection
        domain = url.split('/')[2]
        headers = {"Authorization": f"Bearer {API_KEYS.get(domain, '')}"}

        async with session.get(url, headers=headers, timeout=10) as response:
            if response.status != 200:
                logger.error(f"Error fetching from {url}: HTTP {response.status}")
                return []

            data = await response.json()
            return parse_headlines(data, url)

    except aiohttp.ClientConnectorError:
        logger.error(f"Connection error for {url}")
        return []
    except asyncio.TimeoutError:
        logger.error(f"Request timeout for {url}")
        return []
    except json.JSONDecodeError:
        logger.error(f"JSON parsing error for {url}")
        return []
    except Exception as e:
        logger.error(f"Unexpected error fetching from {url}: {str(e)}")
        return []

def parse_headlines(data, source_url):
    """Parse headlines from different API response formats"""
    headlines = []
    try:
        # Different parsing logic based on API source
        if "api.example.com" in source_url:
            for item in data.get("articles", []):
                headlines.append({
                    "title": item.get("headline", ""),
                    "timestamp": parse_timestamp(item.get("publishedAt")),
                    "source": "Example Finance"
                })
        elif "api.financialnews.org" in source_url:
            for item in data.get("news", []):
                headlines.append({
                    "title": item.get("title", ""),
                    "timestamp": parse_timestamp(item.get("published")),
                    "source": "Financial News Org"
                })
        elif "newsapi.org" in source_url:
            for item in data.get("articles", []):
                headlines.append({
                    "title": item.get("title", ""),
                    "timestamp": parse_timestamp(item.get("publishedAt")),
                    "source": item.get("source", {}).get("name", "NewsAPI")
                })
        elif "market-data-api.com" in source_url:
            for item in data.get("headlines", []):
                headlines.append({
                    "title": item.get("text", ""),
                    "timestamp": parse_timestamp(item.get("timestamp")),
                    "source": "Market Data API"
                })
        return headlines
    except Exception as e:
        logger.error(f"Error parsing data from {source_url}: {str(e)}")
        return []

def parse_timestamp(timestamp_str):
    """Parse various timestamp formats to datetime objects"""
    if not timestamp_str:
        return datetime.now()

    formats = [
        "%Y-%m-%dT%H:%M:%SZ",       # ISO format
        "%Y-%m-%d %H:%M:%S",        # Standard format
        "%Y/%m/%d %H:%M:%S",        # Alternative format
        "%a, %d %b %Y %H:%M:%S %Z"  # RFC format
    ]

    for fmt in formats:
        try:
            return datetime.strptime(timestamp_str, fmt)
        except ValueError:
            continue

    logger.warning(f"Could not parse timestamp: {timestamp_str}")
    return datetime.now()

async def main():
    """Main function to fetch and process financial headlines"""
    async with aiohttp.ClientSession() as session:
        # Create tasks for all API endpoints
        tasks = [fetch_news(session, url) for url in API_ENDPOINTS]

        # Execute all requests concurrently
        results = await asyncio.gather(*tasks)

        # Combine all headlines
        all_headlines = []
        for headlines in results:
            all_headlines.extend(headlines)

        # Sort headlines by timestamp
        sorted_headlines = sorted(all_headlines, key=lambda x: x["timestamp"])

        # Print the sorted headlines
        if sorted_headlines:
            print("\nFinancial Headlines (sorted by time):")
            print("-" * 50)
            for headline in sorted_headlines:
                timestamp_str = headline["timestamp"].strftime("%Y-%m-%d %H:%M:%S")
                print(f"[{timestamp_str}] {headline['title']} - {headline['source']}")
        else:
            print("No headlines were retrieved.")

if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("\nOperation cancelled by user")
    except Exception as e:
        logger.critical(f"Fatal error in main execution: {str(e)}")

