package main

import (
	"fmt"
	"log"
	"os"
	"strconv"

	"github.com/jinzhu/gorm"
	_ "github.com/jinzhu/gorm/dialects/postgres"
	"github.com/sirupsen/logrus"
)

// Book represents book data in the inventory
type Book struct {
	gorm.Model
	Title    string `gorm:"not null"`
	Author   string `gorm:"not null"`
	ISBN     string `gorm:"unique;not null"`
	Quantity int    `gorm:"not null"`
}

// DBHandler manages database operations
type DBHandler struct {
	DB     *gorm.DB
	Logger *logrus.Logger
}

// InitDB initializes database connection
func InitDB() (*gorm.DB, error) {
	// Replace with your PostgreSQL connection details
	db, err := gorm.Open("postgres", "host=localhost port=5432 user=postgres dbname=bookstore password=postgres sslmode=disable")
	if err != nil {
		return nil, err
	}

	// Auto-migrate the Book model
	db.AutoMigrate(&Book{})
	return db, nil
}

// SetupLogger initializes structured logging
func SetupLogger() *logrus.Logger {
	logger := logrus.New()
	logger.SetFormatter(&logrus.JSONFormatter{})
	logger.SetOutput(os.Stdout)
	return logger
}

// NewDBHandler creates a new database handler
func NewDBHandler(db *gorm.DB, logger *logrus.Logger) *DBHandler {
	return &DBHandler{
		DB:     db,
		Logger: logger,
	}
}

// AddBook adds a new book to inventory
func (h *DBHandler) AddBook(title, author, isbn string, quantity int) error {
	book := Book{
		Title:    title,
		Author:   author,
		ISBN:     isbn,
		Quantity: quantity,
	}

	result := h.DB.Create(&book)
	if result.Error != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "create",
			"title":  title,
			"isbn":   isbn,
			"error":  result.Error,
		}).Error("Failed to add book")
		return result.Error
	}

	h.Logger.WithFields(logrus.Fields{
		"action": "create",
		"id":     book.ID,
		"title":  title,
		"isbn":   isbn,
	}).Info("Book added successfully")
	return nil
}

// UpdateBook updates an existing book
func (h *DBHandler) UpdateBook(id uint, title, author, isbn string, quantity int) error {
	var book Book
	if err := h.DB.First(&book, id).Error; err != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "update",
			"id":     id,
			"error":  err,
		}).Error("Book not found")
		return err
	}

	book.Title = title
	book.Author = author
	book.ISBN = isbn
	book.Quantity = quantity

	if err := h.DB.Save(&book).Error; err != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "update",
			"id":     id,
			"error":  err,
		}).Error("Failed to update book")
		return err
	}

	h.Logger.WithFields(logrus.Fields{
		"action": "update",
		"id":     id,
		"title":  title,
		"isbn":   isbn,
	}).Info("Book updated successfully")
	return nil
}

// DeleteBook removes a book from inventory
func (h *DBHandler) DeleteBook(id uint) error {
	var book Book
	if err := h.DB.First(&book, id).Error; err != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "delete",
			"id":     id,
			"error":  err,
		}).Error("Book not found")
		return err
	}

	if err := h.DB.Delete(&book).Error; err != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "delete",
			"id":     id,
			"error":  err,
		}).Error("Failed to delete book")
		return err
	}

	h.Logger.WithFields(logrus.Fields{
		"action": "delete",
		"id":     id,
		"title":  book.Title,
		"isbn":   book.ISBN,
	}).Info("Book deleted successfully")
	return nil
}

// GetBook retrieves a book by ID
func (h *DBHandler) GetBook(id uint) (*Book, error) {
	var book Book
	if err := h.DB.First(&book, id).Error; err != nil {
		h.Logger.WithFields(logrus.Fields{
			"action": "read",
			"id":     id,
			"error":  err,
		}).Error("Book not found")
		return nil, err
	}

	h.Logger.WithFields(logrus.Fields{
		"action": "read",
		"id":     id,
		"title":  book.Title,
		"isbn":   book.ISBN,
	}).Info("Book retrieved successfully")
