package main

import (
	"bufio"
	"encoding/csv"
	"fmt"
	"io"
	"log"
	"os"
	"strconv"
	"sync"
	"time"

	"github.com/asynkron/protoactor-go/actor"
)

// TradeData represents a single stock trade
type TradeData struct {
	Symbol      string
	Price       float64
	Volume      int
	TradingFirm string
	Timestamp   time.Time
}

// TradingFirmActor processes trades for a specific firm
type TradingFirmActor struct {
	firm            string
	totalVolume     int
	highestPrice    float64
	processedTrades int
}

// TradeMessage is sent to trading firm actors
type TradeMessage struct {
	Trade TradeData
}

// VolumeRequest asks for the current trading volume
type VolumeRequest struct{}

// VolumeResponse contains the trading volume data
type VolumeResponse struct {
	Firm         string
	Volume       int
	HighestPrice float64
}

// AggregatorActor collects responses from trading firm actors
type AggregatorActor struct {
	firms        map[string]*actor.PID
	responses    map[string]VolumeResponse
	totalVolume  int
	highestPrice float64
	wg           *sync.WaitGroup
}

// NewTradingFirmActor creates a new trading firm actor
func NewTradingFirmActor(firm string) actor.Producer {
	return func() actor.Actor {
		return &TradingFirmActor{
			firm:         firm,
			totalVolume:  0,
			highestPrice: 0,
		}
	}
}

// Receive handles messages sent to the trading firm actor
func (t *TradingFirmActor) Receive(context actor.Context) {
	switch msg := context.Message().(type) {
	case *TradeMessage:
		// Process trade data
		t.processedTrades++
		t.totalVolume += msg.Trade.Volume

		if msg.Trade.Price > t.highestPrice {
			t.highestPrice = msg.Trade.Price
		}

	case *VolumeRequest:
		// Respond with current trading volume and highest price
		context.Respond(&VolumeResponse{
			Firm:         t.firm,
			Volume:       t.totalVolume,
			HighestPrice: t.highestPrice,
		})
	}
}

// NewAggregatorActor creates a new aggregator actor
func NewAggregatorActor(wg *sync.WaitGroup) actor.Producer {
	return func() actor.Actor {
		return &AggregatorActor{
			firms:        make(map[string]*actor.PID),
			responses:    make(map[string]VolumeResponse),
			totalVolume:  0,
			highestPrice: 0,
			wg:           wg,
		}
	}
}

// Receive handles messages sent to the aggregator actor
func (a *AggregatorActor) Receive(context actor.Context) {
	switch msg := context.Message().(type) {
	case *TradeData:
		// Get or create trading firm actor
		firm := msg.TradingFirm
		pid, exists := a.firms[firm]
		if !exists {
			props := actor.PropsFromProducer(NewTradingFirmActor(firm))
			pid = context.Spawn(props)
			a.firms[firm] = pid
		}

		// Send trade data to trading firm actor
		context.Send(pid, &TradeMessage{Trade: *msg})

	case string:
		if msg == "collect" {
			// Request volume data from all trading firm actors
			a.responses = make(map[string]VolumeResponse)
			a.totalVolume = 0
			a.highestPrice = 0

			for firm, pid := range a.firms {
				future := context.RequestFuture(pid, &VolumeRequest{}, 5*time.Second)
				go func(firmName string) {
					result, err := future.Result()
					if err != nil {
						log.Printf("Error getting response from %s: %v", firmName, err)
						return
					}

					response := result.(*VolumeResponse)
					context.Send(context.Self(), response)
				}(firm)
			}
		}

	case *VolumeResponse:
		// Collect response from trading firm actor
		a.responses[msg.Firm] = *msg
		a.totalVolume += msg.Volume

		if msg.HighestPrice > a.highestPrice {
			a.highestPrice = msg.HighestPrice
		}

		// Check if all responses have been collected
		if len(a.responses) == len(a.firms) {
			fmt.Printf("Total trading volume: %d\n", a.totalVolume)
			fmt.Printf("Highest stock price: %.2f\n", a.highestPrice)

			// Print per-firm statistics
			fmt.Println("\nPer-firm statistics:")
			for firm, response := range a.responses {
				fmt.Printf("Firm: %s, Volume: %d, Highest Price: %.2f\n", 
					firm, response.Volume, response.HighestPrice)
			}

			a.wg.Done()
		}
	}
}

func parseTradeData(record []string) (*TradeData, error) {
	if len(record) < 5 {
		return nil, fmt.Errorf("incomplete trade data: %v", record)
	}

	// Parse price
	price, err := strconv.ParseFloat(record[1], 64)
	if err != nil {
		return nil, fmt.Errorf("invalid price %s: %v", record[1], err)
	}

	// Parse volume
	volume, err := strconv.Atoi(record[2])
	if err != nil {
		return nil, fmt.Errorf("invalid volume %s: %v", record[2], err)
	}

	// Parse timestamp
	timestamp, err := time.Parse("2006-01-02T15:04:05", record[4])
	if err != nil {
		return nil, fmt.Errorf("invalid timestamp %s: %v", record[4], err)
	}

	return &TradeData{
		Symbol:      record[0],
		Price:       price,
		Volume:      volume,
		TradingFirm: record[3],
		Timestamp:   timestamp,
	}, nil
}

func main() {
	// Initialize actor system
	system := actor.NewActorSystem()

	// Create wait group to ensure processing completes
	var wg sync.WaitGroup
	wg.Add(1)

	// Create aggregator actor
	aggregatorProps := actor.PropsFromProducer(NewAggregatorActor(&wg))
	aggregator := system.Root.Spawn(aggregatorProps)

	// Open and read CSV file
	file, err := os.Open("trading_data.csv")
	if err != nil {
		log.Fatalf("Error opening file: %v", err)
	}
	defer file.Close()

	// Skip header line
	reader := csv.NewReader(bufio.NewReader(file))
	_, err = reader.Read()
	if err != nil {
		log.Fatalf("Error reading header: %v", err)
	}

	// Process each line in the CSV
	lineCount := 0
	errorCount := 0
	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			log.Printf("Error reading line: %v", err)
			errorCount++
			continue
		}

		lineCount++

		// Parse trade data
		trade, err := parseTradeData(record)
		if err != nil {
			log.Printf("Error parsing line %d: %v", lineCount, err)
			errorCount++
			continue
		}

		// Send trade data to aggregator actor
		system.Root.Send(aggregator, trade)
	}

	// Request volume collection
	system.Root.Send(aggregator, "collect")

	// Wait for processing to complete
	wg.Wait()

	// Log processing summary
	fmt.Printf("\nProcessing summary:\n")
	fmt.Printf("Total lines processed: %d\n", lineCount)
	fmt.Printf("Errors encountered: %d\n", errorCount)
}

import asyncio
import csv
import httpx
import sys
from typing import Dict, List, Tuple, Optional

async def fetch_news(client: httpx.AsyncClient, country: str, api_key: str) -> Optional[Dict]:
    """Fetch news articles for a specific country."""
    url = f"https://newsapi.org/v2/top-headlines"
    params = {
        "country": country,
        "apiKey": api_key
    }

    try:
        response = await client.get(url, params=params)
        response.raise_for_status()
        return response.json()
    except httpx.HTTPStatusError as e:
        print(f"Error fetching news for {country}: {e.response.status_code}")
        return None
    except httpx.RequestError as e:
        print(f"Request error for {country}: {str(e)}")
        return None

def parse_csv(file_path: str) -> List[Tuple[str, int]]:
    """Parse the CSV file containing country codes and minimum article counts."""
    country_data = []

    try:
        with open(file_path, 'r', newline='') as csvfile:
            reader = csv.reader(csvfile)
            header = next(reader, None)  # Skip header row

            for row in reader:
                try:
                    if len(row) < 2:
                        print(f"Skipping malformed row: {row}")
                        continue

                    country_name = row[0].strip()
                    min_count = int(row[1].strip())
                    country_data.append((country_name, min_count))
                except ValueError as e:
                    print(f"Error parsing row {row}: {str(e)}")
                    continue
    except FileNotFoundError:
        print(f"File not found: {file_path}")
        sys.exit(1)
    except Exception as e:
        print(f"Error reading CSV file: {str(e)}")
        sys.exit(1)

    return country_data

async def main():
    if len(sys.argv) != 3:
        print("Usage: python script.py <countries_csv_file> <api_key>")
        sys.exit(1)

    csv_file = sys.argv[1]
    api_key = sys.argv[2]

    # Parse the CSV file
    country_data = parse_csv(csv_file)

    if not country_data:
        print("No valid country data found in the CSV file.")
        sys.exit(1)

    # Process news for each country asynchronously
    async with httpx.AsyncClient() as client:
        tasks = []
        for country_name, min_count in country_data:
            task = fetch_news(client, country_name, api_key)
            tasks.append((country_name, min_count, task))

        results = {}
        for country_name, min_count, task in tasks:
            news_data = await task
            if news_data and "articles" in news_data:
                qualifying_articles = [
                    article for article in news_data["articles"]
                    if article.get("title") and article.get("description")
                ]

                if len(qualifying_articles) >= min_count:
                    results[country_name] = len(qualifying_articles)
                else:
                    results[country_name] = 0
            else:
                results[country_name] = 0

    # Print summary of results
    print("\nNews API Results Summary:")
    print("-----------------------")
    for country_name, article_count in results.items():
        print(f"{country_name}: {article_count} qualifying articles")

if __name__ == "__main__":
    asyncio.run(main())

