import axios from 'axios';
import { match, P } from 'ts-pattern';

// Define types for API responses
interface Character {
  name: string;
  gender: string;
  birth_year: string;
  height: string;
  mass: string;
  species: string[];
  url: string;
}

interface ApiResponse {
  results: Character[];
  count: number;
  next: string | null;
  previous: string | null;
}

// Function to fetch character data
async function fetchCharacterData(id: number): Promise<void> {
  try {
    const response = await axios.get(`https://swapi.dev/api/people/${id}/`);

    // Fetch species information if available
    let speciesName = "Unknown";
    if (response.data.species && response.data.species.length > 0) {
      const speciesResponse = await axios.get(response.data.species[0]);
      speciesName = speciesResponse.data.name;
    }

    const characterData = { ...response.data, species: speciesName };

    // Use ts-pattern to match and extract properties
    match(characterData)
      .with({ name: P.string, gender: P.string, species: P.string }, (character) => {
        console.log(`Name: ${character.name}`);
        console.log(`Gender: ${character.gender}`);
        console.log(`Species: ${character.species}`);
        console.log('---');
      })
      .with({ name: P.string, gender: P.string }, (character) => {
        console.log(`Name: ${character.name}`);
        console.log(`Gender: ${character.gender}`);
        console.log('Species: Unknown');
        console.log('---');
      })
      .with({ name: P.string }, (character) => {
        console.log(`Name: ${character.name}`);
        console.log('Other data unavailable');
        console.log('---');
      })
      .otherwise((data) => {
        console.log('Unexpected data format:', data);
        console.log('---');
      });
  } catch (error) {
    match(error)
      .with({ response: { status: 404 } }, () => {
        console.error('Character not found');
      })
      .with({ response: { status: P.number } }, (err) => {
        console.error(`API Error: Status ${err.response.status}`);
      }) 
      .with({ request: P._ }, () => {
        console.error('Network Error: No response received');
      })
      .otherwise((err) => {
        console.error('Unexpected error:', err);
      });
  }
}

// Function to fetch multiple characters
async function fetchMultipleCharacters(): Promise<void> {
  try {
    const response = await axios.get<ApiResponse>('https://swapi.dev/api/people/');

    match(response)
      .with({ data: { results: P.array(P._) } }, async (res) => {
        for (const character of res.data.results) {
          // Fetch species information if available
          let speciesName = "Unknown";
          if (character.species && character.species.length > 0) {
            try {
              const speciesResponse = await axios.get(character.species[0]);
              speciesName = speciesResponse.data.name;
            } catch (err) {
              // Species fetch failed, keep as unknown
            }
          }

          // Format and print character information
          match({ ...character, species: speciesName })
            .with({ 
              name: P.string,
              gender: P.string,
              species: P.string,
              height: P.string,
              mass: P.string  
            }, (char) => {
              console.log(`Name: ${char.name}`);
              console.log(`Gender: ${char.gender}`);
              console.log(`Species: ${char.species}`);
              console.log(`Height: ${char.height} cm`);
              console.log(`Mass: ${char.mass} kg`);
              console.log('---');
            })
            .with({ name: P.string, gender: P.string }, (char) => {
              console.log(`Name: ${char.name}`);
              console.log(`Gender: ${char.gender}`);
              console.log(`Species: ${char.species}`);
              console.log('Additional data unavailable');
              console.log('---');
            })
            .otherwise((data) => {
              console.log('Incomplete data:', data.name || 'Unknown character');
              console.log('---');
            });
        }
      })
      .with({ data: P._ }, () => {
        console.log('Unexpected API response format');
      })
      .otherwise(() => {
        console.log('Invalid response');
      });
  } catch (error) {
    match(error)
      .with({ response: { status: P.number } }, (err) => {
        console.error(`API Error: Status ${err.response.status}`);
      })
      .with({ request: P._ }, () => {
        console.error('Network Error: No response received');
      })
      .otherwise((err) => {
        console.error('Unexpected error:', err);
      });
  }
}

// Main function
async function main() {
  console.log('Fetching individual character:');
  await fetchCharacterData(1);

  console.log('\nFetching multiple characters:');
  await fetchMultipleCharacters();
}

