import (
	"sync"
)

// sumConcurrently calculates the sum of an array concurrently using goroutines
// Generic type parameter T is constrained to numeric types
func sumConcurrently[T int | int8 | int16 | int32 | int64 | uint | uint8 | uint16 | uint32 | uint64 | float32 | float64](arr []T) T {
	var sum T
	var mu sync.Mutex
	var wg sync.WaitGroup

	// Determine the number of goroutines
	numRoutines := 4
	if len(arr) < numRoutines {
		numRoutines = len(arr)
	}

	// Calculate the chunk size for each goroutine
	chunkSize := len(arr) / numRoutines
	if chunkSize == 0 {
		chunkSize = 1
	}

	// Launch goroutines to process chunks
	for i := 0; i < numRoutines; i++ {
		wg.Add(1)
		start := i * chunkSize
		end := start + chunkSize
		if i == numRoutines-1 {
			end = len(arr)
		}

		go func(start, end int) {
			defer wg.Done()
			var partialSum T
			for j := start; j < end; j++ {
				partialSum += arr[j]
			}
			mu.Lock()
			sum += partialSum
			mu.Unlock()
		}(start, end)
	}

	// Wait for all goroutines to finish
	wg.Wait()
	return sum
}
