import requests
import json
import logging
import sys
import time
from typing import Dict, Any, Optional

class WeatherAPIClient:
    def __init__(self, base_url: str, api_key: str, max_retries: int = 3, retry_delay: int = 2):
        self.base_url = base_url
        self.api_key = api_key
        self.max_retries = max_retries
        self.retry_delay = retry_delay
        self.logger = self._setup_logger()

    def _setup_logger(self) -> logging.Logger:
        logger = logging.getLogger("WeatherAPIClient")
        logger.setLevel(logging.INFO)

        # Create console handler
        handler = logging.StreamHandler()
        formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
        handler.setFormatter(formatter)
        logger.addHandler(handler)

        # Log Python version
        python_version = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"
        logger.info(f"Initializing WeatherAPIClient with Python {python_version}")

        return logger

    def get_weather(self, city: str) -> Optional[Dict[str, Any]]:
        params = {
            'q': city,
            'appid': self.api_key
        }

        for attempt in range(self.max_retries):
            try:
                self.logger.info(f"Requesting weather data for {city} (Attempt {attempt + 1}/{self.max_retries})")
                response = requests.get(f"{self.base_url}", params=params, timeout=10)
                response.raise_for_status()

                data = response.json()
                self.logger.info(f"Successfully retrieved weather data for {city}")

                return self._parse_weather_data(data)

            except requests.exceptions.HTTPError as e:
                self.logger.error(f"HTTP error: {e}")
                if response.status_code == 404:
                    self.logger.error(f"City '{city}' not found")
                    return None

            except requests.exceptions.ConnectionError:
                self.logger.error(f"Connection error. Retrying in {self.retry_delay} seconds...")

            except requests.exceptions.Timeout:
                self.logger.error(f"Request timed out. Retrying in {self.retry_delay} seconds...")

            except requests.exceptions.RequestException as e:
                self.logger.error(f"Request error: {e}")

            except json.JSONDecodeError:
                self.logger.error("Failed to parse JSON response")

            if attempt < self.max_retries - 1:
                time.sleep(self.retry_delay)
            else:
                self.logger.error(f"Failed to retrieve weather data after {self.max_retries} attempts")

        return None

    def _parse_weather_data(self, data: Dict[str, Any]) -> Dict[str, Any]:
        try:
            result = {
                "city": data.get("name", "Unknown"),
                "temperature": {
                    "value": data.get("main", {}).get("temp", 0),
                    "unit": "K"  # Assuming Kelvin as default unit
                },
                "humidity": {
                    "value": data.get("main", {}).get("humidity", 0),
                    "unit": "%"
                },
                "conditions": data.get("weather", [{}])[0].get("description", "Unknown")
            }
            return result
        except (KeyError, IndexError) as e:
            self.logger.error(f"Error parsing weather data: {e}")
            raise

    def format_weather_output(self, weather_data: Dict[str, Any]) -> str:
        if not weather_data:
            return "No weather data available."

        city = weather_data.get("city", "Unknown")
        temp = weather_data.get("temperature", {}).get("value", 0)
        temp_unit = weather_data.get("temperature", {}).get("unit", "K")
        humidity = weather_data.get("humidity", {}).get("value", 0)
        humidity_unit = weather_data.get("humidity", {}).get("unit", "%")
        conditions = weather_data.get("conditions", "Unknown")

        output = f"""
Weather for {city}:
--------------------
Temperature: {temp} {temp_unit}
Humidity: {humidity} {humidity_unit}
Conditions: {conditions}
--------------------
        """

        return output

# Example usage
if __name__ == "__main__":
    # Configuration
    API_ENDPOINT = "https://api.openweathermap.org/data/2.5/weather"
    API_KEY = "your_api_key_here"

    # Create client
    client = WeatherAPIClient(API_ENDPOINT, API_KEY)

    # Get weather data
    weather_data = client.get_weather("London")

    # Format and display output
    if weather_data:
        formatted_output = client.format_weather_output(weather_data)
        print(formatted_output)
